// ─── Contexto de Autenticación AutoSlot ──────────────────
import React, { createContext, useContext, useState } from 'react';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [usuario, setUsuario] = useState(
    () => JSON.parse(localStorage.getItem('autoslot_user') || 'null')
  );

  // Login simulado — en producción conectar con el backend
  const login = (email, password) => {
    if (email === 'admin@autoslot.com' && password === 'admin123') {
      const user = { nombre: 'Administrador', email, rol: 'ADMIN' };
      setUsuario(user);
      localStorage.setItem('autoslot_user', JSON.stringify(user));
      return { success: true };
    }
    return { success: false, mensaje: 'Credenciales incorrectas' };
  };

  const logout = () => {
    setUsuario(null);
    localStorage.removeItem('autoslot_user');
  };

  return (
    <AuthContext.Provider value={{ usuario, login, logout, isAuth: !!usuario }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
